import subprocess, tempfile, os, signal

def execute_with_timeout(code: str, test_input: str, timeout: int = 5) -> dict:
    """
    Execute generated code against a single test case.
    Returns {passed: bool, runtime_ms: float, error: str|None}.
    """
    with tempfile.NamedTemporaryFile(suffix='.py', mode='w', delete=False) as f:
        f.write(code)
        path = f.name

    try:
        proc = subprocess.run(
            ['python3', path],
            input=test_input, capture_output=True, text=True,
            timeout=timeout,
        )
        return {
            'passed': proc.returncode == 0,
            'stdout': proc.stdout,
            'stderr': proc.stderr,
            'timed_out': False,
        }
    except subprocess.TimeoutExpired:
        return {'passed': False, 'stdout': '', 'stderr': 'Timeout', 'timed_out': True}
    finally:
        os.unlink(path)


def compute_reward(code: str, test_cases: list[dict],
                   timeout: int = 5, style_bonus: float = 0.05) -> float:
    """
    Compute reward for a generated program over a list of test cases.
    Each test case: {'input': str, 'expected_output': str}.
    """
    if not test_cases:
        return 0.0

    passed = 0
    timed_out = False
    for tc in test_cases:
        result = execute_with_timeout(code, tc['input'], timeout)
        if result['timed_out']:
            timed_out = True
            break
        if result['passed'] and result['stdout'].strip() == tc['expected_output'].strip():
            passed += 1

    if timed_out:
        return 0.0

    pass_rate = passed / len(test_cases)

    # Style bonus: check with flake8 (ignores line-length)
    bonus = 0.0
    if pass_rate > 0:
        try:
            r = subprocess.run(['flake8', '--max-line-length=120', '-'],
                               input=code, capture_output=True, text=True)
            if r.returncode == 0:
                bonus = style_bonus
        except FileNotFoundError:
            pass   # flake8 not installed — skip bonus

    return pass_rate + bonus
